  1→package com.exam.controller;
  2→
  3→import com.exam.dto.Result;
  4→import com.exam.dto.UserInfo;
  5→import com.exam.service.AuthService;
  6→import jakarta.servlet.http.HttpServletRequest;
  7→import lombok.extern.slf4j.Slf4j;
  8→import org.springframework.beans.factory.annotation.Value;
  9→import org.springframework.http.HttpHeaders;
 10→import org.springframework.http.HttpStatus;
 11→import org.springframework.http.ResponseEntity;
 12→import org.springframework.security.core.Authentication;
 13→import org.springframework.security.core.context.SecurityContextHolder;
 14→import org.springframework.web.bind.annotation.GetMapping;
 15→import org.springframework.web.bind.annotation.RequestMapping;
 16→import org.springframework.web.bind.annotation.RequestParam;
 17→import org.springframework.web.bind.annotation.RestController;
 18→import org.springframework.web.util.UriComponentsBuilder;
 19→
 20→/**
 21→ * 认证接口：OAuth2 登录、回调、获取当前用户
 22→ */
 23→@Slf4j
 24→@RestController
 25→@RequestMapping("/api/auth")
 26→public class AuthController {
 27→
 28→    private final AuthService authService;
 29→
 30→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 31→    private String clientId;
 32→
 33→    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
 34→    private String authorizationUri;
 35→
 36→    @Value("${spring.security.oauth2.client.registration.default.scope:openid,profile,email}")
 37→    private String scope;
 38→
 39→    public AuthController(AuthService authService) {
 40→        this.authService = authService;
 41→    }
 42→
 43→    /**
 44→     * 构建 OA 授权地址并 302 重定向
 45→     */
 46→    @GetMapping("/oauth2/login")
 47→    public ResponseEntity<Void> login(HttpServletRequest request) {
 48→        String redirectUri = buildRedirectUri(request);
 49→
 50→        String authorizeUrl = UriComponentsBuilder.fromHttpUrl(authorizationUri)
 51→                .queryParam("client_id", clientId)
 52→                .queryParam("redirect_uri", redirectUri)
 53→                .queryParam("response_type", "code")
 54→                .queryParam("scope", scope)
 55→                .toUriString();
 56→
 57→        log.debug("[exam-auth] OAuth2 登录重定向: {}", authorizeUrl);
 58→
 59→        return ResponseEntity.status(HttpStatus.FOUND)
 60→                .header(HttpHeaders.LOCATION, authorizeUrl)
 61→                .build();
 62→    }
 63→
 64→    /**
 65→     * OAuth2 回调：用 code 换 token
 66→     */
 67→    @GetMapping("/oauth2/callback")
 68→    public Result<String> callback(@RequestParam("code") String code,
 69→                                   HttpServletRequest request) {
 70→        String redirectUri = buildRedirectUri(request);
 71→        String token = authService.handleOAuthCallback(code, redirectUri);
 72→        log.info("[exam-auth] OAuth2 回调完成, 已签发 token");
 73→        return Result.ok(token);
 74→    }
 75→
 76→    /**
 77→     * 获取当前登录用户信息
 78→     */
 79→    @GetMapping("/me")
 80→    public Result<UserInfo> me() {
 81→        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
 82→        Long userId = Long.parseLong(auth.getName());
 83→        UserInfo userInfo = authService.getCurrentUser(userId);
 84→        return Result.ok(userInfo);
 85→    }
 86→
 87→    /**
 88→     * 根据当前请求构建 OAuth2 回调地址
 89→     */
 90→    private String buildRedirectUri(HttpServletRequest request) {
 91→        String scheme = request.getScheme();
 92→        String serverName = request.getServerName();
 93→        int serverPort = request.getServerPort();
 94→
 95→        StringBuilder sb = new StringBuilder();
 96→        sb.append(scheme).append("://").append(serverName);
 97→        // 非标准端口时拼接
 98→        if (("http".equals(scheme) && serverPort != 80)
 99→                || ("https".equals(scheme) && serverPort != 443)) {
100→            sb.append(":").append(serverPort);
101→        }
102→        sb.append("/api/auth/oauth2/callback");
103→        return sb.toString();
104→    }
105→}
