 1→import { getToken, logout } from "./auth"
 2→
 3→/** 后端统一响应结构 */
 4→interface ApiResponse<T> {
 5→  code: number
 6→  message: string
 7→  data: T
 8→}
 9→
10→/**
11→ * 通用 fetch 封装
12→ * - 自动携带 Authorization header
13→ * - 401 时清除 token 并跳转登录
14→ * - 解析统一响应结构，code !== 200 时抛出异常
15→ */
16→async function request<T>(
17→  url: string,
18→  options: RequestInit = {},
19→): Promise<T> {
20→  const token = getToken()
21→
22→  const headers: Record<string, string> = {
23→    "Content-Type": "application/json",
24→    ...(options.headers as Record<string, string>),
25→  }
26→
27→  if (token) {
28→    headers.Authorization = `Bearer ${token}`
29→  }
30→
31→  const res = await fetch(url, { ...options, headers })
32→
33→  // 401 未授权：清除 token，跳转登录页
34→  if (res.status === 401) {
35→    logout()
36→    throw new Error("Unauthorized")
