package com.exam.controller.admin;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.exam.dto.ExamCreateRequest;
import com.exam.dto.ExamListResponse;
import com.exam.dto.ExamUpdateRequest;
import com.exam.dto.Result;
import com.exam.entity.Exam;
import com.exam.service.ExamService;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

/**
 * 管理员 - 试卷管理接口
 */
@Slf4j
@RestController
@RequestMapping("/api/admin/exams")
public class AdminExamController {

    private final ExamService examService;

    public AdminExamController(ExamService examService) {
        this.examService = examService;
    }

    @GetMapping
    public Result<IPage<ExamListResponse>> listExams(
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size) {
        return Result.ok(examService.listExams(page, size));
    }

    @PostMapping
    public Result<Exam> create(@Valid @RequestBody ExamCreateRequest req) {
        Long userId = Long.parseLong(
                SecurityContextHolder.getContext().getAuthentication().getName());
        log.info("[lbl][Exam][CREATE] 创建试卷请求, title={}, userId={}", req.getTitle(), userId);
        return Result.ok(examService.create(req, userId));
    }

    @PutMapping("/{id}")
    public Result<Void> update(@PathVariable Long id,
                               @Valid @RequestBody ExamUpdateRequest req) {
        log.info("[lbl][Exam][UPDATE] 更新试卷请求, examId={}, title={}", id, req.getTitle());
        examService.update(id, req);
        return Result.ok();
    }

    @DeleteMapping("/{id}")
    public Result<Void> delete(@PathVariable Long id) {
        log.info("[lbl][Exam][DELETE] 删除试卷请求, examId={}", id);
        examService.delete(id);
        return Result.ok();
    }

    @PutMapping("/{id}/publish")
