358→    private boolean hasAccess(Exam exam, Long userId) {
359→        if (exam.getAccessMode() == AccessMode.OPEN) {
360→            return true;
361→        }
362→        // 白名单模式：检查用户是否在白名单中
363→        long count = examWhitelistMapper.selectCount(
364→                new LambdaQueryWrapper<ExamWhitelist>()
