381→    /**
382→     * 抽题逻辑：随机抽取指定数量的题目
383→     */
384→    private List<QuestionBank> drawQuestions(List<QuestionBank> allQuestions, Integer questionCount) {
385→        List<QuestionBank> pool = new ArrayList<>(allQuestions);
386→        if (questionCount == null || questionCount == 0 || questionCount >= pool.size()) {
387→            // 使用全部题目，打乱顺序
388→            Collections.shuffle(pool);
389→            return pool;
390→        }
391→        // 随机抽取指定数量
392→        Collections.shuffle(pool);
393→        List<QuestionBank> selected = new ArrayList<>(pool.subList(0, questionCount));
394→        // 再次打乱保证随机顺序
395→        Collections.shuffle(selected);
396→        return selected;
397→    }
