 17→/**
 18→ * 白名单服务
 19→ */
 20→@Slf4j
 21→@Service
 22→public class WhitelistService {
 23→
 24→    private final ExamWhitelistMapper examWhitelistMapper;
 25→    private final SysUserMapper sysUserMapper;
 26→
 27→    public WhitelistService(ExamWhitelistMapper examWhitelistMapper, SysUserMapper sysUserMapper) {
 28→        this.examWhitelistMapper = examWhitelistMapper;
 29→        this.sysUserMapper = sysUserMapper;
 30→    }
 31→
 32→    /**
 33→     * 查询考试白名单用户列表
 34→     */
 35→    public List<UserInfo> list(Long examId) {
 36→        List<ExamWhitelist> whitelistEntries = examWhitelistMapper.selectList(
 37→                new LambdaQueryWrapper<ExamWhitelist>().eq(ExamWhitelist::getExamId, examId));
 38→        if (whitelistEntries.isEmpty()) {
 39→            return Collections.emptyList();
 40→        }
 41→
 42→        List<Long> userIds = whitelistEntries.stream()
 43→                .map(ExamWhitelist::getUserId)
 44→                .collect(Collectors.toList());
 45→
 46→        List<SysUser> users = sysUserMapper.selectBatchIds(userIds);
 47→
 48→        return users.stream().map(user -> {
 49→            UserInfo info = new UserInfo();
 50→            info.setId(user.getId());
 51→            info.setOaUserId(user.getOaUserId());
 52→            info.setUsername(user.getUsername());
 53→            info.setDisplayName(user.getDisplayName());
 54→            info.setIsAdmin(user.getIsAdmin());
 55→            return info;
 56→        }).collect(Collectors.toList());
 57→    }
 58→
 59→    /**
 60→     * 批量添加白名单用户（已存在的跳过）
 61→     */
 62→    public int batchAdd(Long examId, List<Long> userIds) {
 63→        // 查询已存在的白名单记录
 64→        List<ExamWhitelist> existing = examWhitelistMapper.selectList(
 65→                new LambdaQueryWrapper<ExamWhitelist>()
 66→                        .eq(ExamWhitelist::getExamId, examId)
 67→                        .in(ExamWhitelist::getUserId, userIds));
 68→
 69→        Set<Long> existingUserIds = existing.stream()
 70→                .map(ExamWhitelist::getUserId)
 71→                .collect(Collectors.toSet());
 72→
 73→        int added = 0;
 74→        for (Long userId : userIds) {
 75→            if (existingUserIds.contains(userId)) {
 76→                continue;
 77→            }
 78→            ExamWhitelist entry = ExamWhitelist.builder()
 79→                    .examId(examId)
 80→                    .userId(userId)
 81→                    .build();
 82→            examWhitelistMapper.insert(entry);
 83→            added++;
