package com.exam.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.exam.dto.UserInfo;
import com.exam.entity.ExamWhitelist;
import com.exam.entity.SysUser;
import com.exam.mapper.ExamWhitelistMapper;
import com.exam.mapper.SysUserMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

/**
 * 白名单服务
 */
@Slf4j
@Service
public class WhitelistService {

    private final ExamWhitelistMapper examWhitelistMapper;
    private final SysUserMapper sysUserMapper;

    public WhitelistService(ExamWhitelistMapper examWhitelistMapper, SysUserMapper sysUserMapper) {
        this.examWhitelistMapper = examWhitelistMapper;
        this.sysUserMapper = sysUserMapper;
    }

    /**
     * 查询考试白名单用户列表
     */
    public List<UserInfo> list(Long examId) {
        List<ExamWhitelist> whitelistEntries = examWhitelistMapper.selectList(
                new LambdaQueryWrapper<ExamWhitelist>().eq(ExamWhitelist::getExamId, examId));
        if (whitelistEntries.isEmpty()) {
            return Collections.emptyList();
        }

        List<Long> userIds = whitelistEntries.stream()
                .map(ExamWhitelist::getUserId)
                .collect(Collectors.toList());

        List<SysUser> users = sysUserMapper.selectBatchIds(userIds);

        return users.stream().map(user -> {
            UserInfo info = new UserInfo();
            info.setId(user.getId());
            info.setOaUserId(user.getOaUserId());
            info.setUsername(user.getUsername());
            info.setDisplayName(user.getDisplayName());
            info.setIsAdmin(user.getIsAdmin());
            return info;
        }).collect(Collectors.toList());
    }

    /**
     * 批量添加白名单用户（已存在的跳过）
     */
    public int batchAdd(Long examId, List<Long> userIds) {
        // 查询已存在的白名单记录
        List<ExamWhitelist> existing = examWhitelistMapper.selectList(
                new LambdaQueryWrapper<ExamWhitelist>()
                        .eq(ExamWhitelist::getExamId, examId)
                        .in(ExamWhitelist::getUserId, userIds));

        Set<Long> existingUserIds = existing.stream()
                .map(ExamWhitelist::getUserId)
                .collect(Collectors.toSet());

        int added = 0;
        for (Long userId : userIds) {
            if (existingUserIds.contains(userId)) {
                continue;
            }
            ExamWhitelist entry = ExamWhitelist.builder()
                    .examId(examId)
                    .userId(userId)
                    .build();
            examWhitelistMapper.insert(entry);
            added++;
        }

        log.info("[lbl][Whitelist][ADD] 批量添加白名单, examId={}, addedCount={}", examId, added);
        return added;
    }

    /**
     * 批量移除白名单用户
     */
    public int batchRemove(Long examId, List<Long> userIds) {
        int removed = examWhitelistMapper.delete(
                new LambdaQueryWrapper<ExamWhitelist>()
                        .eq(ExamWhitelist::getExamId, examId)
                        .in(ExamWhitelist::getUserId, userIds));

        log.info("[lbl][Whitelist][REMOVE] 批量移除白名单, examId={}, removedCount={}", examId, removed);
        return removed;
    }
}

