/**
 * 考试系统 - 全量接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 前置: 后端以 dev profile 启动（start-backend.bat）
 *
 * 覆盖 27 个接口，13 个测试维度
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://localhost:18080',
  frontendUrl: 'http://localhost:5173',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let token = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
async function rawFetch(method, url, body) {
  const headers = { 'content-type': 'application/json' };
  if (token) headers['authorization'] = `Bearer ${token}`;

  const opts = { method, headers, redirect: 'manual' };
  if (body !== undefined) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}${path}`, body);
  return res.json();
}

async function PUT(path, body) {
  const res = await rawFetch('PUT', `${CONFIG.host}${path}`, body);
  return res.json();
}

async function DEL(path, body) {
  const res = await rawFetch('DELETE', `${CONFIG.host}${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========
async function login() {
  console.log('🔑 通过 dev profile 获取 JWT ...');
  const res = await rawFetch('GET', `${CONFIG.host}/api/auth/oauth2/login`);
  const location = res.headers.get('location');
  if (!location || !location.includes('token=')) {
    console.log('❌ 登录失败: 未获取到 redirect location', location);
    process.exit(1);
  }
  token = new URL(location).searchParams.get('token');
  console.log(`   ✅ 登录成功, token=${token.substring(0, 20)}...\n`);
}

let savedToken = '';
function saveSession() { savedToken = token; }
function restoreSession() { token = savedToken; }

// ========== 测试数据追踪 ==========
let testExamId = null;        // 测试创建的试卷 ID
let testQuestionIds = [];     // 测试创建的题目 ID 列表
let testRecordId = null;      // 考试记录 ID

// ========== 维度 1: 正常流程 — 管理员 CRUD ==========
async function testAdminExamCrud() {
  console.log('📋 1. 管理员试卷 CRUD');

  // 创建试卷
  const createRes = await POST('/api/admin/exams', {
    title: '自动化测试试卷_' + Date.now(),
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 3,
    accessMode: 'open',
  });
  assert('创建试卷 code=200', createRes.code === 200, createRes);
  assert('返回 data.id', createRes.data?.id != null, createRes.data);
  assert('返回 data.status=draft', createRes.data?.status === 'draft', createRes.data?.status);
  testExamId = createRes.data?.id;

  // 查询列表
  const listRes = await GET('/api/admin/exams?page=1&size=10');
  assert('列表 code=200', listRes.code === 200, listRes);
  assert('列表含 records 数组', Array.isArray(listRes.data?.records), listRes.data);
  assert('列表含 total', typeof listRes.data?.total === 'number', listRes.data?.total);

  if (listRes.data?.records?.length > 0) {
    const first = listRes.data.records[0];
    assert('记录含 id', first.id != null);
    assert('记录含 title (string)', typeof first.title === 'string');
    assert('记录含 status', first.status != null);
    assert('记录含 questionCount', typeof first.questionCount === 'number');
    assert('记录含 respondentCount', typeof first.respondentCount === 'number');
  }

  // 更新试卷
  const updateRes = await PUT(`/api/admin/exams/${testExamId}`, {
    title: '更新后的试卷_' + Date.now(),
    timeLimitMin: 60,
    showAnswer: false,
    showAnalysis: false,
    questionCount: 2,
    maxAttempts: 5,
    accessMode: 'whitelist',
  });
  assert('更新试卷 code=200', updateRes.code === 200, updateRes);
}

// ========== 维度 1: 正常流程 — 题目 CRUD ==========
async function testQuestionCrud() {
  console.log('\n📋 1b. 题目 CRUD');

  // 先把试卷改回 open + draft（update 要求 draft 状态）
  await PUT(`/api/admin/exams/${testExamId}`, {
    title: '测试试卷_含题目_' + Date.now(),
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });

  // 创建单个题目
  const q1 = await POST(`/api/admin/exams/${testExamId}/questions`, {
    content: '1+1=?',
    optionA: '1',
    optionB: '2',
    optionC: '3',
    optionD: '4',
    correctAnswer: 'B',
    analysis: '基础数学',
  });
  assert('创建题目 code=200', q1.code === 200, q1);
  assert('返回 questionId', q1.data?.id != null, q1.data);
  testQuestionIds.push(q1.data?.id);

  // 批量导入题目
  const batchRes = await POST(`/api/admin/exams/${testExamId}/questions/batch`, {
    questions: [
      { content: '2+2=?', optionA: '3', optionB: '4', optionC: '5', optionD: '6', correctAnswer: 'B', analysis: '加法' },
      { content: '3+3=?', optionA: '5', optionB: '6', optionC: '7', optionD: '8', correctAnswer: 'B', analysis: '加法' },
    ],
  });
  assert('批量导入 code=200', batchRes.code === 200, batchRes);
  assert('批量导入返回数量=2', batchRes.data === 2, batchRes.data);

  // 查询题目列表
  const listQ = await GET(`/api/admin/exams/${testExamId}/questions`);
  assert('题目列表 code=200', listQ.code === 200, listQ);
  assert('题目列表是数组', Array.isArray(listQ.data), listQ.data);
  assert('题目数量>=3', listQ.data?.length >= 3, listQ.data?.length);

  // 记录所有题目 ID
  if (listQ.data) {
    testQuestionIds = listQ.data.map(q => q.id);
  }

  // 更新题目
  const updateQ = await PUT(`/api/admin/questions/${testQuestionIds[0]}`, {
    content: '更新后: 1+1=?',
    optionA: '0',
    optionB: '2',
    optionC: '3',
    optionD: '4',
    correctAnswer: 'B',
    analysis: '更新后的解析',
  });
  assert('更新题目 code=200', updateQ.code === 200, updateQ);
}

// ========== 维度 1: 正常流程 — 试卷状态流转 ==========
async function testExamStatusFlow() {
  console.log('\n📋 1c. 试卷状态流转');

  // draft -> published
  const pub = await PUT(`/api/admin/exams/${testExamId}/publish`);
  assert('发布试卷 code=200', pub.code === 200, pub);

  // published -> unpublish -> draft
  const unpub = await PUT(`/api/admin/exams/${testExamId}/unpublish`);
  assert('取消发布 code=200', unpub.code === 200, unpub);

  // draft -> published (再次)
  const pub2 = await PUT(`/api/admin/exams/${testExamId}/publish`);
  assert('再次发布 code=200', pub2.code === 200, pub2);

  // published -> closed
  const close = await PUT(`/api/admin/exams/${testExamId}/close`);
  assert('关闭试卷 code=200', close.code === 200, close);

  // closed -> reopen -> published
  const reopen = await PUT(`/api/admin/exams/${testExamId}/reopen`);
  assert('重新发布 code=200', reopen.code === 200, reopen);
}

// ========== 维度 1: 正常流程 — 考生端考试 ==========
async function testStudentExamFlow() {
  console.log('\n📋 1d. 考生端考试流程');

  // 考试列表
  const exams = await GET('/api/exams?page=1&size=10');
  assert('考试列表 code=200', exams.code === 200, exams);
  assert('列表含 records', Array.isArray(exams.data?.records), exams.data);

  // 考试详情
  const detail = await GET(`/api/exams/${testExamId}`);
  assert('考试详情 code=200', detail.code === 200, detail);
  assert('详情含 title', typeof detail.data?.title === 'string', detail.data);
  assert('详情含 status=published', detail.data?.status === 'published', detail.data?.status);
  assert('详情含 remainingAttempts', detail.data?.remainingAttempts !== undefined);

  // 开始考试
  const start = await POST(`/api/exams/${testExamId}/start`);
  assert('开始考试 code=200', start.code === 200, start);
  assert('返回 recordId', start.data?.recordId != null, start.data);
  assert('返回 questions 数组', Array.isArray(start.data?.questions), start.data);
  assert('题目不含 correctAnswer', start.data?.questions?.[0]?.correctAnswer == null);
  assert('题目不含 analysis', start.data?.questions?.[0]?.analysis == null);
  testRecordId = start.data?.recordId;

  // 构建答案
  const answers = (start.data?.questions || []).map(q => ({
    questionId: q.id,
    answer: 'B',
  }));

  // 提交考试
  const submit = await POST(`/api/exams/${testExamId}/submit`, {
    recordId: testRecordId,
    answers,
  });
  assert('提交考试 code=200', submit.code === 200, submit);
  assert('返回 score', submit.data?.score != null, submit.data);
  assert('返回 status', submit.data?.status != null, submit.data?.status);

  // 考试记录列表
  const records = await GET('/api/records?page=1&size=10');
  assert('记录列表 code=200', records.code === 200, records);
  assert('记录含 records', Array.isArray(records.data?.records));
  assert('记录数量>=1', records.data?.records?.length >= 1);

  if (records.data?.records?.length > 0) {
    const rec = records.data.records[0];
    assert('记录含 id', rec.id != null);
    assert('记录含 examTitle', typeof rec.examTitle === 'string');
    assert('记录含 score', rec.score != null);
    assert('记录含 status', rec.status != null);
    assert('记录含 attemptNo', rec.attemptNo != null);
    assert('列表中 answers 为 null', rec.answers == null);
  }

  // 记录详情
  const recordDetail = await GET(`/api/records/${testRecordId}`);
  assert('记录详情 code=200', recordDetail.code === 200, recordDetail);
  assert('详情含 answers 数组', Array.isArray(recordDetail.data?.answers), recordDetail.data);
  if (recordDetail.data?.answers?.length > 0) {
    const ans = recordDetail.data.answers[0];
    assert('答题含 questionId', ans.questionId != null);
    assert('答题含 userAnswer', ans.userAnswer != null);
    assert('答题含 isCorrect', ans.isCorrect != null);
    assert('答题含 content', typeof ans.content === 'string');
    assert('showAnswer=true 时含 correctAnswer', ans.correctAnswer != null);
    assert('showAnalysis=true 时含 analysis', ans.analysis != null);
  }
}

// ========== 维度 1: 正常流程 — 白名单 ==========
async function testWhitelist() {
  console.log('\n📋 1e. 白名单管理');

  // 获取当前用户 ID
  const me = await GET('/api/auth/me');
  assert('获取当前用户 code=200', me.code === 200, me);
  const myUserId = me.data?.id;

  // 查询白名单（空）
  const list1 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  assert('白名单列表 code=200', list1.code === 200, list1);
  assert('初始白名单是数组', Array.isArray(list1.data));

  // 添加白名单
  const addRes = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
  assert('添加白名单 code=200', addRes.code === 200, addRes);
  assert('添加数量>=0', addRes.data >= 0, addRes.data);

  // 再查白名单
  const list2 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  assert('添加后白名单有记录', list2.data?.length > 0, list2.data?.length);

  // 删除白名单
  const removeRes = await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
  assert('移除白名单 code=200', removeRes.code === 200, removeRes);

  // 确认移除
  const list3 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  const found = list3.data?.find(u => u.id === myUserId);
  assert('移除后不在白名单中', !found);
}

// ========== 维度 1: 正常流程 — 数据分析 ==========
async function testAnalysis() {
  console.log('\n📋 1f. 数据分析');

  // 成绩分析
  const scores = await GET(`/api/admin/exams/${testExamId}/analysis/scores?page=1&size=10`);
  assert('成绩分析 code=200', scores.code === 200, scores);
  assert('成绩含 records', Array.isArray(scores.data?.records));
  if (scores.data?.records?.length > 0) {
    const s = scores.data.records[0];
    assert('成绩含 userId', s.userId != null);
    assert('成绩含 displayName', s.displayName != null);
    assert('成绩含 score', s.score != null);
    assert('成绩含 attemptNo', s.attemptNo != null);
  }

  // 题目分析
  const questions = await GET(`/api/admin/exams/${testExamId}/analysis/questions`);
  assert('题目分析 code=200', questions.code === 200, questions);
  assert('题目分析是数组', Array.isArray(questions.data));
  if (questions.data?.length > 0) {
    const q = questions.data[0];
    assert('题目含 questionId', q.questionId != null);
    assert('题目含 content', typeof q.content === 'string');
    assert('题目含 totalAnswered', typeof q.totalAnswered === 'number');
    assert('题目含 correctCount', typeof q.correctCount === 'number');
    assert('题目含 correctRate', q.correctRate != null);
  }
}

// ========== 维度 2: 分页边界 ==========
async function testPaginationBoundary() {
  console.log('\n📐 2. 分页边界');

  // admin 列表
  const p1 = await GET('/api/admin/exams?page=1&size=1');
  assert('pageSize=1 最多返回1条', p1.data?.records?.length <= 1);

  const p100 = await GET('/api/admin/exams?page=1&size=100');
  assert('pageSize=100 返回成功', p100.code === 200);

  if (p100.data?.total <= 100) {
    assert('total<=100 时 length===total', p100.data.records.length === p100.data.total);
  }

  const overPage = await GET('/api/admin/exams?page=9999&size=10');
  assert('超页返回空列表', overPage.data?.records?.length === 0);
  assert('超页 total 不变', overPage.data?.total === p100.data?.total);

  // 两页不重复
  if (p1.data?.total > 1) {
    const p2 = await GET('/api/admin/exams?page=2&size=1');
    assert('第2页有数据', p2.data?.records?.length > 0);
