/**
 * 考试系统 - 全量接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 前置: 后端以 dev profile 启动（start-backend.bat）
 *
 * 覆盖 27 个接口，13 个测试维度
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://localhost:18080',
  frontendUrl: 'http://localhost:5173',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let token = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
async function rawFetch(method, url, body) {
  const headers = { 'content-type': 'application/json' };
  if (token) headers['authorization'] = `Bearer ${token}`;

  const opts = { method, headers, redirect: 'manual' };
  if (body !== undefined) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}${path}`, body);
  return res.json();
}

async function PUT(path, body) {
  const res = await rawFetch('PUT', `${CONFIG.host}${path}`, body);
  return res.json();
}

async function DEL(path, body) {
  const res = await rawFetch('DELETE', `${CONFIG.host}${path}`, body);
  return res.json();
}

// ========== 登录管理 ==========
async function login() {
  console.log('🔑 通过 dev profile 获取 JWT ...');
  const res = await rawFetch('GET', `${CONFIG.host}/api/auth/oauth2/login`);
  const location = res.headers.get('location');
  if (!location || !location.includes('token=')) {
    console.log('❌ 登录失败: 未获取到 redirect location', location);
    process.exit(1);
  }
  token = new URL(location).searchParams.get('token');
  console.log(`   ✅ 登录成功, token=${token.substring(0, 20)}...\n`);
}

let savedToken = '';
function saveSession() { savedToken = token; }
function restoreSession() { token = savedToken; }

// ========== 测试数据追踪 ==========
let testExamId = null;        // 测试创建的试卷 ID
let testQuestionIds = [];     // 测试创建的题目 ID 列表
let testRecordId = null;      // 考试记录 ID

// ========== 维度 1: 正常流程 — 管理员 CRUD ==========
async function testAdminExamCrud() {
  console.log('📋 1. 管理员试卷 CRUD');

  // 创建试卷
  const createRes = await POST('/api/admin/exams', {
    title: '自动化测试试卷_' + Date.now(),
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 3,
    accessMode: 'open',
  });
  assert('创建试卷 code=200', createRes.code === 200, createRes);
  assert('返回 data.id', createRes.data?.id != null, createRes.data);
  assert('返回 data.status=draft', createRes.data?.status === 'draft', createRes.data?.status);
  testExamId = createRes.data?.id;

  // 查询列表
  const listRes = await GET('/api/admin/exams?page=1&size=10');
  assert('列表 code=200', listRes.code === 200, listRes);
  assert('列表含 records 数组', Array.isArray(listRes.data?.records), listRes.data);
  assert('列表含 total', typeof listRes.data?.total === 'number', listRes.data?.total);

  if (listRes.data?.records?.length > 0) {
    const first = listRes.data.records[0];
    assert('记录含 id', first.id != null);
    assert('记录含 title (string)', typeof first.title === 'string');
    assert('记录含 status', first.status != null);
    assert('记录含 questionCount', typeof first.questionCount === 'number');
    assert('记录含 respondentCount', typeof first.respondentCount === 'number');
  }

  // 更新试卷
  const updateRes = await PUT(`/api/admin/exams/${testExamId}`, {
    title: '更新后的试卷_' + Date.now(),
    timeLimitMin: 60,
    showAnswer: false,
    showAnalysis: false,
    questionCount: 2,
    maxAttempts: 5,
    accessMode: 'whitelist',
  });
  assert('更新试卷 code=200', updateRes.code === 200, updateRes);
}

// ========== 维度 1: 正常流程 — 题目 CRUD ==========
async function testQuestionCrud() {
  console.log('\n📋 1b. 题目 CRUD');

  // 先把试卷改回 open + draft（update 要求 draft 状态）
  await PUT(`/api/admin/exams/${testExamId}`, {
    title: '测试试卷_含题目_' + Date.now(),
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });

  // 创建单个题目
  const q1 = await POST(`/api/admin/exams/${testExamId}/questions`, {
    content: '1+1=?',
    optionA: '1',
    optionB: '2',
    optionC: '3',
    optionD: '4',
    correctAnswer: 'B',
    analysis: '基础数学',
  });
  assert('创建题目 code=200', q1.code === 200, q1);
  assert('返回 questionId', q1.data?.id != null, q1.data);
  testQuestionIds.push(q1.data?.id);

  // 批量导入题目
  const batchRes = await POST(`/api/admin/exams/${testExamId}/questions/batch`, {
    questions: [
      { content: '2+2=?', optionA: '3', optionB: '4', optionC: '5', optionD: '6', correctAnswer: 'B', analysis: '加法' },
      { content: '3+3=?', optionA: '5', optionB: '6', optionC: '7', optionD: '8', correctAnswer: 'B', analysis: '加法' },
    ],
  });
  assert('批量导入 code=200', batchRes.code === 200, batchRes);
  assert('批量导入返回数量=2', batchRes.data === 2, batchRes.data);

  // 查询题目列表
  const listQ = await GET(`/api/admin/exams/${testExamId}/questions`);
  assert('题目列表 code=200', listQ.code === 200, listQ);
  assert('题目列表是数组', Array.isArray(listQ.data), listQ.data);
  assert('题目数量>=3', listQ.data?.length >= 3, listQ.data?.length);

  // 记录所有题目 ID
  if (listQ.data) {
    testQuestionIds = listQ.data.map(q => q.id);
  }

  // 更新题目
  const updateQ = await PUT(`/api/admin/questions/${testQuestionIds[0]}`, {
    content: '更新后: 1+1=?',
    optionA: '0',
    optionB: '2',
    optionC: '3',
    optionD: '4',
    correctAnswer: 'B',
    analysis: '更新后的解析',
  });
  assert('更新题目 code=200', updateQ.code === 200, updateQ);
}

// ========== 维度 1: 正常流程 — 试卷状态流转 ==========
async function testExamStatusFlow() {
  console.log('\n📋 1c. 试卷状态流转');

  // draft -> published
  const pub = await PUT(`/api/admin/exams/${testExamId}/publish`);
  assert('发布试卷 code=200', pub.code === 200, pub);

  // published -> unpublish -> draft
  const unpub = await PUT(`/api/admin/exams/${testExamId}/unpublish`);
  assert('取消发布 code=200', unpub.code === 200, unpub);

  // draft -> published (再次)
  const pub2 = await PUT(`/api/admin/exams/${testExamId}/publish`);
  assert('再次发布 code=200', pub2.code === 200, pub2);

  // published -> closed
  const close = await PUT(`/api/admin/exams/${testExamId}/close`);
  assert('关闭试卷 code=200', close.code === 200, close);

  // closed -> reopen -> published
  const reopen = await PUT(`/api/admin/exams/${testExamId}/reopen`);
  assert('重新发布 code=200', reopen.code === 200, reopen);
}

// ========== 维度 1: 正常流程 — 考生端考试 ==========
async function testStudentExamFlow() {
  console.log('\n📋 1d. 考生端考试流程');

  // 考试列表
  const exams = await GET('/api/exams?page=1&size=10');
  assert('考试列表 code=200', exams.code === 200, exams);
  assert('列表含 records', Array.isArray(exams.data?.records), exams.data);

  // 考试详情
  const detail = await GET(`/api/exams/${testExamId}`);
  assert('考试详情 code=200', detail.code === 200, detail);
  assert('详情含 title', typeof detail.data?.title === 'string', detail.data);
  assert('详情含 status=published', detail.data?.status === 'published', detail.data?.status);
  assert('详情含 remainingAttempts', detail.data?.remainingAttempts !== undefined);

  // 开始考试
  const start = await POST(`/api/exams/${testExamId}/start`);
  assert('开始考试 code=200', start.code === 200, start);
  assert('返回 recordId', start.data?.recordId != null, start.data);
  assert('返回 questions 数组', Array.isArray(start.data?.questions), start.data);
  assert('题目不含 correctAnswer', start.data?.questions?.[0]?.correctAnswer == null);
  assert('题目不含 analysis', start.data?.questions?.[0]?.analysis == null);
  testRecordId = start.data?.recordId;

  // 构建答案
  const answers = (start.data?.questions || []).map(q => ({
    questionId: q.id,
    answer: 'B',
  }));

  // 提交考试
  const submit = await POST(`/api/exams/${testExamId}/submit`, {
    recordId: testRecordId,
    answers,
  });
  assert('提交考试 code=200', submit.code === 200, submit);
  assert('返回 score', submit.data?.score != null, submit.data);
  assert('返回 status', submit.data?.status != null, submit.data?.status);

  // 考试记录列表
  const records = await GET('/api/records?page=1&size=10');
  assert('记录列表 code=200', records.code === 200, records);
  assert('记录含 records', Array.isArray(records.data?.records));
  assert('记录数量>=1', records.data?.records?.length >= 1);

  if (records.data?.records?.length > 0) {
    const rec = records.data.records[0];
    assert('记录含 id', rec.id != null);
    assert('记录含 examTitle', typeof rec.examTitle === 'string');
    assert('记录含 score', rec.score != null);
    assert('记录含 status', rec.status != null);
    assert('记录含 attemptNo', rec.attemptNo != null);
    assert('列表中 answers 为 null', rec.answers == null);
  }

  // 记录详情
  const recordDetail = await GET(`/api/records/${testRecordId}`);
  assert('记录详情 code=200', recordDetail.code === 200, recordDetail);
  assert('详情含 answers 数组', Array.isArray(recordDetail.data?.answers), recordDetail.data);
  if (recordDetail.data?.answers?.length > 0) {
    const ans = recordDetail.data.answers[0];
    assert('答题含 questionId', ans.questionId != null);
    assert('答题含 userAnswer', ans.userAnswer != null);
    assert('答题含 isCorrect', ans.isCorrect != null);
    assert('答题含 content', typeof ans.content === 'string');
    assert('showAnswer=true 时含 correctAnswer', ans.correctAnswer != null);
    assert('showAnalysis=true 时含 analysis', ans.analysis != null);
  }
}

// ========== 维度 1: 正常流程 — 白名单 ==========
async function testWhitelist() {
  console.log('\n📋 1e. 白名单管理');

  // 获取当前用户 ID
  const me = await GET('/api/auth/me');
  assert('获取当前用户 code=200', me.code === 200, me);
  const myUserId = me.data?.id;

  // 查询白名单（空）
  const list1 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  assert('白名单列表 code=200', list1.code === 200, list1);
  assert('初始白名单是数组', Array.isArray(list1.data));

  // 添加白名单
  const addRes = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
  assert('添加白名单 code=200', addRes.code === 200, addRes);
  assert('添加数量>=0', addRes.data >= 0, addRes.data);

  // 再查白名单
  const list2 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  assert('添加后白名单有记录', list2.data?.length > 0, list2.data?.length);

  // 删除白名单
  const removeRes = await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myUserId] });
  assert('移除白名单 code=200', removeRes.code === 200, removeRes);

  // 确认移除
  const list3 = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  const found = list3.data?.find(u => u.id === myUserId);
  assert('移除后不在白名单中', !found);
}

// ========== 维度 1: 正常流程 — 数据分析 ==========
async function testAnalysis() {
  console.log('\n📋 1f. 数据分析');

  // 成绩分析
  const scores = await GET(`/api/admin/exams/${testExamId}/analysis/scores?page=1&size=10`);
  assert('成绩分析 code=200', scores.code === 200, scores);
  assert('成绩含 records', Array.isArray(scores.data?.records));
  if (scores.data?.records?.length > 0) {
    const s = scores.data.records[0];
    assert('成绩含 userId', s.userId != null);
    assert('成绩含 displayName', s.displayName != null);
    assert('成绩含 score', s.score != null);
    assert('成绩含 attemptNo', s.attemptNo != null);
  }

  // 题目分析
  const questions = await GET(`/api/admin/exams/${testExamId}/analysis/questions`);
  assert('题目分析 code=200', questions.code === 200, questions);
  assert('题目分析是数组', Array.isArray(questions.data));
  if (questions.data?.length > 0) {
    const q = questions.data[0];
    assert('题目含 questionId', q.questionId != null);
    assert('题目含 content', typeof q.content === 'string');
    assert('题目含 totalAnswered', typeof q.totalAnswered === 'number');
    assert('题目含 correctCount', typeof q.correctCount === 'number');
    assert('题目含 correctRate', q.correctRate != null);
  }
}

// ========== 维度 2: 分页边界 ==========
async function testPaginationBoundary() {
  console.log('\n📐 2. 分页边界');

  // admin 列表
  const p1 = await GET('/api/admin/exams?page=1&size=1');
  assert('pageSize=1 最多返回1条', p1.data?.records?.length <= 1);

  const p100 = await GET('/api/admin/exams?page=1&size=100');
  assert('pageSize=100 返回成功', p100.code === 200);

  if (p100.data?.total <= 100) {
    assert('total<=100 时 length===total', p100.data.records.length === p100.data.total);
  }

  const overPage = await GET('/api/admin/exams?page=9999&size=10');
  assert('超页返回空列表', overPage.data?.records?.length === 0);
  assert('超页 total 不变', overPage.data?.total === p100.data?.total);

  // 两页不重复
  if (p1.data?.total > 1) {
    const p2 = await GET('/api/admin/exams?page=2&size=1');
    assert('第2页有数据', p2.data?.records?.length > 0);
    if (p2.data?.records?.length > 0) {
      assert('两页 ID 不重复', p1.data.records[0].id !== p2.data.records[0].id);
    }
  }

  // 不传分页参数（用默认值）
  const noPage = await GET('/api/admin/exams');
  assert('不传分页用默认值 code=200', noPage.code === 200);

  // 考生端分页
  const ep1 = await GET('/api/exams?page=1&size=1');
  assert('考生端 pageSize=1 code=200', ep1.code === 200);

  const ep9999 = await GET('/api/exams?page=9999&size=10');
  assert('考生端超页返回空列表', ep9999.data?.records?.length === 0);

  // 记录分页
  const rp1 = await GET('/api/records?page=1&size=1');
  assert('记录 pageSize=1 code=200', rp1.code === 200);

  const rp9999 = await GET('/api/records?page=9999&size=10');
  assert('记录超页返回空列表', rp9999.data?.records?.length === 0);

  // 成绩分析分页
  const sp1 = await GET(`/api/admin/exams/${testExamId}/analysis/scores?page=1&size=1`);
  assert('成绩分析 pageSize=1 code=200', sp1.code === 200);
}

// ========== 维度 3: 搜索边界（考试系统无搜索接口，跳过，标注原因） ==========
// 当前接口无 keyword/search 参数，无需搜索测试

// ========== 维度 4: 参数校验 ==========
async function testParamValidation() {
  console.log('\n🔒 4. 参数校验');

  // 创建试卷缺少必填字段 title
  const noTitle = await POST('/api/admin/exams', {
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('缺少 title 返回错误', noTitle.code !== 200, noTitle);

  // 创建试卷空 title
  const emptyTitle = await POST('/api/admin/exams', {
    title: '',
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('空 title 返回错误', emptyTitle.code !== 200, emptyTitle);

  // 创建试卷纯空格 title
  const spaceTitle = await POST('/api/admin/exams', {
    title: '   ',
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('空格 title 返回错误', spaceTitle.code !== 200, spaceTitle);

  // 缺少 accessMode
  const noMode = await POST('/api/admin/exams', {
    title: '测试',
    timeLimitMin: 30,
    showAnswer: true,
    showAnalysis: true,
  });
  assert('缺少 accessMode 返回错误', noMode.code !== 200, noMode);

  // timeLimitMin 负数
  const negTime = await POST('/api/admin/exams', {
    title: '测试负数',
    timeLimitMin: -1,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('timeLimitMin=-1 返回错误', negTime.code !== 200, negTime);

  // 创建题目缺少必填字段
  const noContent = await POST(`/api/admin/exams/${testExamId}/questions`, {
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  assert('题目缺少 content 返回错误', noContent.code !== 200, noContent);

  // correctAnswer 非法值
  const badAnswer = await POST(`/api/admin/exams/${testExamId}/questions`, {
    content: '测试题',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'E',
  });
  assert('correctAnswer=E 返回错误', badAnswer.code !== 200, badAnswer);

  // 提交考试 answers 为空
  const emptyAnswers = await POST(`/api/exams/${testExamId}/submit`, {
    recordId: 1,
    answers: [],
  });
  assert('空 answers 返回错误', emptyAnswers.code !== 200, emptyAnswers);

  // 白名单空列表
  const emptyWhitelist = await POST(`/api/admin/exams/${testExamId}/whitelist`, {
    userIds: [],
  });
  assert('空 userIds 返回错误', emptyWhitelist.code !== 200, emptyWhitelist);

  // 批量导入空题目列表
  const emptyBatch = await POST(`/api/admin/exams/${testExamId}/questions/batch`, {
    questions: [],
  });
  assert('空题目列表返回错误', emptyBatch.code !== 200, emptyBatch);

  // AnswerItem answer 不合法
  const badItem = await POST(`/api/exams/${testExamId}/submit`, {
    recordId: 1,
    answers: [{ questionId: 1, answer: 'X' }],
  });
  assert('answer=X 返回校验错误', badItem.code !== 200, badItem);
}

// ========== 维度 5: 特殊字符与注入防护 ==========
async function testInjection() {
  console.log('\n🛡️ 5. 注入防护 + 特殊字符');

  // 特殊字符作为 title
  const specialChars = ['<script>alert(1)</script>', "'; DROP TABLE ex_exam; --", '测试\n换行', '测试\t制表'];
  for (const title of specialChars) {
    const res = await POST('/api/admin/exams', {
      title,
      timeLimitMin: 0,
      showAnswer: true,
      showAnalysis: true,
      questionCount: 0,
      maxAttempts: 0,
      accessMode: 'open',
    });
    assert(`特殊字符title "${title.slice(0, 20)}" 不报500`, res.code !== 500, res.code);
    // 如果创建成功，清理
    if (res.code === 200 && res.data?.id) {
      await DEL(`/api/admin/exams/${res.data.id}`);
    }
  }

  // 超长 title（500字符）
  const longTitle = 'A'.repeat(500);
  const longRes = await POST('/api/admin/exams', {
    title: longTitle,
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('超长 title 不报500', longRes.code !== 500, longRes.code);
  if (longRes.code === 200 && longRes.data?.id) {
    await DEL(`/api/admin/exams/${longRes.data.id}`);
  }
}

// ========== 维度 6: 写操作验证 ==========
async function testWriteAndVerify() {
  console.log('\n⚡ 6. 写操作验证');

  // 创建 → 查询验证
  const createRes = await POST('/api/admin/exams', {
    title: '写操作验证_' + Date.now(),
    timeLimitMin: 10,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 1,
    accessMode: 'open',
  });
  const newId = createRes.data?.id;
  assert('创建成功', newId != null);

  // 更新 → 查询列表验证
  const newTitle = '写操作验证_更新后_' + Date.now();
  await PUT(`/api/admin/exams/${newId}`, {
    title: newTitle,
    timeLimitMin: 20,
    showAnswer: false,
    showAnalysis: false,
    questionCount: 0,
    maxAttempts: 2,
    accessMode: 'open',
  });

  const listRes = await GET('/api/admin/exams?page=1&size=100');
  const found = listRes.data?.records?.find(e => e.id === newId);
  assert('更新后 title 已变更', found?.title === newTitle, found?.title);

  // 删除 → 验证消失
  await DEL(`/api/admin/exams/${newId}`);
  const listRes2 = await GET('/api/admin/exams?page=1&size=100');
  const notFound = listRes2.data?.records?.find(e => e.id === newId);
  assert('删除后不在列表中', !notFound);

  // 幂等性：删除已删除的
  const delAgain = await DEL(`/api/admin/exams/${newId}`);
  assert('重复删除返回错误(非500)', delAgain.code !== 200 && delAgain.code !== 500, delAgain.code);
}

// ========== 维度 7: 权限测试 ==========
async function testPermissions() {
  console.log('\n👤 7. 权限测试');

  // 未登录访问
  saveSession();
  token = '';

  const noAuthMe = await GET('/api/auth/me');
  assert('未登录 /api/auth/me 返回 401', noAuthMe.code === 401, noAuthMe.code);

  const noAuthExams = await GET('/api/exams?page=1&size=10');
  assert('未登录 /api/exams 返回 401', noAuthExams.code === 401, noAuthExams.code);

  const noAuthAdmin = await GET('/api/admin/exams?page=1&size=10');
  assert('未登录 /api/admin/exams 返回 401', noAuthAdmin.code === 401, noAuthAdmin.code);

  const noAuthPost = await POST('/api/admin/exams', {
    title: '不应创建',
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('未登录 POST 返回 401', noAuthPost.code === 401, noAuthPost.code);

  // 无效 token
  token = 'invalid.jwt.token';
  const badTokenMe = await GET('/api/auth/me');
  assert('无效 token 返回 401', badTokenMe.code === 401, badTokenMe.code);

  restoreSession();
}

// ========== 维度 8: 不存在/异常数据 ==========
async function testNotExistData() {
  console.log('\n🚫 8. 不存在的数据');

  // 不存在的试卷 ID（用合法 Long 值）
  const fakeId = 999999;

  const detailRes = await GET(`/api/exams/${fakeId}`);
  assert('不存在试卷详情 非500', detailRes.code !== 500, detailRes.code);

  const startRes = await POST(`/api/exams/${fakeId}/start`);
  assert('不存在试卷开始考试 非500', startRes.code !== 500, startRes.code);

  const updateRes = await PUT(`/api/admin/exams/${fakeId}`, {
    title: '不存在',
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('不存在试卷更新 返回404', updateRes.code === 404, updateRes.code);

  const delRes = await DEL(`/api/admin/exams/${fakeId}`);
  assert('不存在试卷删除 返回404', delRes.code === 404, delRes.code);

  const pubRes = await PUT(`/api/admin/exams/${fakeId}/publish`);
  assert('不存在试卷发布 返回404', pubRes.code === 404, pubRes.code);

  // 不存在的题目 ID
  const updateQ = await PUT(`/api/admin/questions/${fakeId}`, {
    content: '不存在',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  assert('不存在题目更新 返回404', updateQ.code === 404, updateQ.code);

  const delQ = await DEL(`/api/admin/questions/${fakeId}`);
  assert('不存在题目删除 返回404', delQ.code === 404, delQ.code);

  // 不存在的考试记录
  const recordDetail = await GET(`/api/records/${fakeId}`);
  assert('不存在记录详情 非500', recordDetail.code !== 500, recordDetail.code);

  // 白名单不存在的试卷
  const wl = await GET(`/api/admin/exams/${fakeId}/whitelist`);
  assert('不存在试卷白名单 code=200', wl.code === 200, wl.code);

  // 分析不存在的试卷
  const scores = await GET(`/api/admin/exams/${fakeId}/analysis/scores?page=1&size=10`);
  assert('不存在试卷成绩分析 code=200(空)', scores.code === 200, scores.code);

  const qAnalysis = await GET(`/api/admin/exams/${fakeId}/analysis/questions`);
  assert('不存在试卷题目分析 code=200(空)', qAnalysis.code === 200, qAnalysis.code);
}

// ========== 维度 9: 并发请求 ==========
async function testConcurrency() {
  console.log('\n🔀 9. 并发请求');

  // 5个并发 GET
  const promises = Array.from({ length: 5 }, (_, i) =>
    GET(`/api/admin/exams?page=${i + 1}&size=5`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.code === 200);
  assert('5个并发 GET 都成功', allOk);

  // 5个并发考生端列表
  const studentPromises = Array.from({ length: 5 }, () =>
    GET('/api/exams?page=1&size=5')
  );
  const studentResults = await Promise.all(studentPromises);
  const allStudentOk = studentResults.every(r => r.code === 200);
  assert('5个并发考生端列表都成功', allStudentOk);
}

// ========== 维度 10: 响应结构一致性 ==========
async function testResponseStructure() {
  console.log('\n📦 10. 响应结构一致性');

  // 分页接口结构一致
  const endpoints = [
    { name: 'admin exams', path: '/api/admin/exams?page=1&size=5' },
    { name: 'student exams', path: '/api/exams?page=1&size=5' },
    { name: 'records', path: '/api/records?page=1&size=5' },
    { name: 'score analysis', path: `/api/admin/exams/${testExamId}/analysis/scores?page=1&size=5` },
  ];

  for (const ep of endpoints) {
    const res = await GET(ep.path);
    assert(`${ep.name} code=200`, res.code === 200, res.code);
    assert(`${ep.name} 含 current/pages`, res.data?.current != null || res.data?.size != null);
    assert(`${ep.name} 含 total`, typeof res.data?.total === 'number');
    assert(`${ep.name} 含 records`, Array.isArray(res.data?.records));
    assert(`${ep.name} records.length<=5`, (res.data?.records?.length || 0) <= 5);
  }

  // 非分页列表接口
  const listEndpoints = [
    { name: 'questions', path: `/api/admin/exams/${testExamId}/questions` },
    { name: 'whitelist', path: `/api/admin/exams/${testExamId}/whitelist` },
    { name: 'question analysis', path: `/api/admin/exams/${testExamId}/analysis/questions` },
  ];

  for (const ep of listEndpoints) {
    const res = await GET(ep.path);
    assert(`${ep.name} code=200`, res.code === 200);
    assert(`${ep.name} data 是数组`, Array.isArray(res.data));
  }
}

// ========== 维度 11: 状态约束测试（替代批量接口维度） ==========
async function testStatusConstraints() {
  console.log('\n🔐 11. 状态约束测试');

  // 创建一个新试卷来测试状态约束
  const res = await POST('/api/admin/exams', {
    title: '状态约束测试_' + Date.now(),
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  const constraintExamId = res.data?.id;

  // draft 状态不能 close
  const closeDraft = await PUT(`/api/admin/exams/${constraintExamId}/close`);
  assert('草稿不能 close', closeDraft.code !== 200, closeDraft.code);

  // draft 状态不能 unpublish
  const unpubDraft = await PUT(`/api/admin/exams/${constraintExamId}/unpublish`);
  assert('草稿不能 unpublish', unpubDraft.code !== 200, unpubDraft.code);

  // draft 状态不能 reopen
  const reopenDraft = await PUT(`/api/admin/exams/${constraintExamId}/reopen`);
  assert('草稿不能 reopen', reopenDraft.code !== 200, reopenDraft.code);

  // 无题目不能发布
  const pubNoQ = await PUT(`/api/admin/exams/${constraintExamId}/publish`);
  assert('无题目不能发布', pubNoQ.code !== 200, pubNoQ.code);
  assert('错误码=1003', pubNoQ.code === 1003, pubNoQ.code);

  // 添加题目后发布
  await POST(`/api/admin/exams/${constraintExamId}/questions`, {
    content: '约束测试题',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  await PUT(`/api/admin/exams/${constraintExamId}/publish`);

  // published 不能 publish 重复发布
  const pubAgain = await PUT(`/api/admin/exams/${constraintExamId}/publish`);
  assert('已发布不能再 publish', pubAgain.code !== 200, pubAgain.code);

  // published 不能 reopen
  const reopenPub = await PUT(`/api/admin/exams/${constraintExamId}/reopen`);
  assert('已发布不能 reopen', reopenPub.code !== 200, reopenPub.code);

  // published 不能 update
  const updatePub = await PUT(`/api/admin/exams/${constraintExamId}`, {
    title: '不该更新',
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('已发布不能 update', updatePub.code !== 200, updatePub.code);

  // published 不能 delete
  const delPub = await DEL(`/api/admin/exams/${constraintExamId}`);
  assert('已发布不能 delete', delPub.code !== 200, delPub.code);

  // published 不能创建/修改题目
  const addQPub = await POST(`/api/admin/exams/${constraintExamId}/questions`, {
    content: '不该添加',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  assert('已发布不能添加题目', addQPub.code !== 200, addQPub.code);

  // close -> 可以删除
  await PUT(`/api/admin/exams/${constraintExamId}/close`);
  const delClosed = await DEL(`/api/admin/exams/${constraintExamId}`);
  assert('已关闭可以 delete', delClosed.code === 200, delClosed.code);
}

// ========== 维度 12: 数据重复检测 ==========
async function testDuplicateData() {
  console.log('\n🐛 12. 数据重复检测');

  // 白名单重复添加
  const me = await GET('/api/auth/me');
  const myId = me.data?.id;

  const add1 = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });
  assert('第1次添加白名单成功', add1.code === 200);

  const add2 = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });
  assert('第2次添加白名单成功(幂等)', add2.code === 200);
  assert('重复添加返回 added=0', add2.data === 0, add2.data);

  const list = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  const count = list.data?.filter(u => u.id === myId).length;
  assert('重复添加后用户仅出现1次', count === 1, count);

  // 清理
  await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });

  // 考试重复开始（已有进行中的考试）
  // 先关闭再重新发布（确保 published）
  const examStatus = await GET(`/api/exams/${testExamId}`);
  if (examStatus.data?.status !== 'published') {
    // 可能已经被关闭等，跳过
    console.log('  ⚠️ 试卷不是 published 状态，跳过重复考试测试');
    return;
  }

  const start1 = await POST(`/api/exams/${testExamId}/start`);
  if (start1.code === 200) {
    const start2 = await POST(`/api/exams/${testExamId}/start`);
    assert('有进行中考试时不能再次开始', start2.code !== 200, start2.code);
    assert('错误码=1005(EXAM_IN_PROGRESS)', start2.code === 1005, start2.code);

    // 提交第一次考试以清理
    const answers = (start1.data?.questions || []).map(q => ({
      questionId: q.id,
      answer: 'A',
    }));
    await POST(`/api/exams/${testExamId}/submit`, {
      recordId: start1.data?.recordId,
      answers,
    });
  }
}

// ========== 维度 13: 错误码规范性 ==========
async function testErrorCodeStandard() {
  console.log('\n🔢 13. 错误码规范性');

  // 所有业务错误都不应返回500
  const cases = [
    { name: '不存在试卷', fn: () => GET('/api/exams/999999') },
    { name: '重复发布', fn: () => PUT(`/api/admin/exams/${testExamId}/publish`) },
    { name: '不存在记录', fn: () => GET('/api/records/999999') },
    { name: '无效状态操作', fn: () => PUT(`/api/admin/exams/${testExamId}/reopen`) },
  ];

  for (const c of cases) {
    const res = await c.fn();
    assert(`${c.name} 非500`, res.code !== 500, res.code);
  }

  // 参数校验错误码
  const validationRes = await POST('/api/admin/exams', { title: '' });
  assert('参数校验返回400', validationRes.code === 400, validationRes.code);

  // 未登录错误码
  saveSession();
  token = '';
  const authRes = await GET('/api/auth/me');
  assert('未登录返回401', authRes.code === 401, authRes.code);
  restoreSession();
}

// ========== 清理测试数据 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据');

  if (testExamId) {
    // 先取消发布/关闭，确保可以删除
    try {
      await PUT(`/api/admin/exams/${testExamId}/unpublish`);
    } catch (_) { /* ignore */ }
    try {
      await PUT(`/api/admin/exams/${testExamId}/close`);
    } catch (_) { /* ignore */ }

    const delRes = await DEL(`/api/admin/exams/${testExamId}`);
    if (delRes.code === 200) {
      console.log(`  ✅ 已清理测试试卷 ID=${testExamId}`);
    } else {
      console.log(`  ⚠️ 清理试卷失败: ${JSON.stringify(delRes)}`);
    }
  }
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 考试系统 - 全量接口测试\n');

  try {
    await login();

    // 维度 1: 正常流程
    await testAdminExamCrud();
    await testQuestionCrud();
    await testExamStatusFlow();
    await testStudentExamFlow();
    await testWhitelist();
    await testAnalysis();

    // 维度 2: 分页边界
    await testPaginationBoundary();

    // 维度 4: 参数校验
    await testParamValidation();

    // 维度 5: 注入防护
    await testInjection();

    // 维度 6: 写操作验证
    await testWriteAndVerify();

    // 维度 7: 权限测试
    await testPermissions();

    // 维度 8: 不存在数据
    await testNotExistData();

    // 维度 9: 并发请求
    await testConcurrency();

    // 维度 10: 响应结构
    await testResponseStructure();

    // 维度 11: 状态约束
    await testStatusConstraints();

    // 维度 12: 数据重复
    await testDuplicateData();

    // 维度 13: 错误码规范
    await testErrorCodeStandard();

    // 清理
    await cleanup();

  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接后端 http://localhost:18080，请确保后端已启动');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n========================================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`========================================`);
  console.log(`\n覆盖维度:`);
  console.log(`  1. 正常流程 (CRUD + 状态流转 + 考试 + 白名单 + 分析)`);
  console.log(`  2. 分页边界`);
  console.log(`  3. 搜索边界 (当前无搜索接口，跳过)`);
  console.log(`  4. 参数校验`);
  console.log(`  5. 注入防护 + 特殊字符`);
  console.log(`  6. 写操作验证`);
  console.log(`  7. 权限测试 (未登录/无效token)`);
  console.log(`  8. 不存在数据`);
  console.log(`  9. 并发请求`);
  console.log(`  10. 响应结构一致性`);
  console.log(`  11. 状态约束 (状态机违规操作)`);
  console.log(`  12. 数据重复检测`);
  console.log(`  13. 错误码规范性`);
  console.log(`\n覆盖接口: 27 个`);
  console.log(`测试账号: dev_user (isAdmin=true, dev profile 自动创建)`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

