// ========== 维度 11: 状态约束测试（替代批量接口维度） ==========
async function testStatusConstraints() {
  console.log('\n🔐 11. 状态约束测试');

  // 创建一个新试卷来测试状态约束
  const res = await POST('/api/admin/exams', {
    title: '状态约束测试_' + Date.now(),
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  const constraintExamId = res.data?.id;

  // draft 状态不能 close
  const closeDraft = await PUT(`/api/admin/exams/${constraintExamId}/close`);
  assert('草稿不能 close', closeDraft.code !== 200, closeDraft.code);

  // draft 状态不能 unpublish
  const unpubDraft = await PUT(`/api/admin/exams/${constraintExamId}/unpublish`);
  assert('草稿不能 unpublish', unpubDraft.code !== 200, unpubDraft.code);

  // draft 状态不能 reopen
  const reopenDraft = await PUT(`/api/admin/exams/${constraintExamId}/reopen`);
  assert('草稿不能 reopen', reopenDraft.code !== 200, reopenDraft.code);

  // 无题目不能发布
  const pubNoQ = await PUT(`/api/admin/exams/${constraintExamId}/publish`);
  assert('无题目不能发布', pubNoQ.code !== 200, pubNoQ.code);
  assert('错误码=1003', pubNoQ.code === 1003, pubNoQ.code);

  // 添加题目后发布
  await POST(`/api/admin/exams/${constraintExamId}/questions`, {
    content: '约束测试题',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  await PUT(`/api/admin/exams/${constraintExamId}/publish`);

  // published 不能 publish 重复发布
  const pubAgain = await PUT(`/api/admin/exams/${constraintExamId}/publish`);
  assert('已发布不能再 publish', pubAgain.code !== 200, pubAgain.code);

  // published 不能 reopen
  const reopenPub = await PUT(`/api/admin/exams/${constraintExamId}/reopen`);
  assert('已发布不能 reopen', reopenPub.code !== 200, reopenPub.code);

  // published 不能 update
  const updatePub = await PUT(`/api/admin/exams/${constraintExamId}`, {
    title: '不该更新',
    timeLimitMin: 0,
    showAnswer: true,
    showAnalysis: true,
    questionCount: 0,
    maxAttempts: 0,
    accessMode: 'open',
  });
  assert('已发布不能 update', updatePub.code !== 200, updatePub.code);

  // published 不能 delete
  const delPub = await DEL(`/api/admin/exams/${constraintExamId}`);
  assert('已发布不能 delete', delPub.code !== 200, delPub.code);

  // published 不能创建/修改题目
  const addQPub = await POST(`/api/admin/exams/${constraintExamId}/questions`, {
    content: '不该添加',
    optionA: 'A',
    optionB: 'B',
    optionC: 'C',
    optionD: 'D',
    correctAnswer: 'A',
  });
  assert('已发布不能添加题目', addQPub.code !== 200, addQPub.code);

  // close -> 可以删除
  await PUT(`/api/admin/exams/${constraintExamId}/close`);
  const delClosed = await DEL(`/api/admin/exams/${constraintExamId}`);
  assert('已关闭可以 delete', delClosed.code === 200, delClosed.code);
}

// ========== 维度 12: 数据重复检测 ==========
async function testDuplicateData() {
  console.log('\n🐛 12. 数据重复检测');

  // 白名单重复添加
  const me = await GET('/api/auth/me');
  const myId = me.data?.id;

  const add1 = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });
  assert('第1次添加白名单成功', add1.code === 200);

  const add2 = await POST(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });
  assert('第2次添加白名单成功(幂等)', add2.code === 200);
  assert('重复添加返回 added=0', add2.data === 0, add2.data);

  const list = await GET(`/api/admin/exams/${testExamId}/whitelist`);
  const count = list.data?.filter(u => u.id === myId).length;
  assert('重复添加后用户仅出现1次', count === 1, count);

  // 清理
  await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });

  // 考试重复开始（已有进行中的考试）
  // 先关闭再重新发布（确保 published）
  const examStatus = await GET(`/api/exams/${testExamId}`);
  if (examStatus.data?.status !== 'published') {
    // 可能已经被关闭等，跳过
    console.log('  ⚠️ 试卷不是 published 状态，跳过重复考试测试');
    return;
  }

  const start1 = await POST(`/api/exams/${testExamId}/start`);
  if (start1.code === 200) {
    const start2 = await POST(`/api/exams/${testExamId}/start`);
    assert('有进行中考试时不能再次开始', start2.code !== 200, start2.code);
    assert('错误码=1005(EXAM_IN_PROGRESS)', start2.code === 1005, start2.code);

    // 提交第一次考试以清理
    const answers = (start1.data?.questions || []).map(q => ({
      questionId: q.id,
      answer: 'A',
    }));
    await POST(`/api/exams/${testExamId}/submit`, {
      recordId: start1.data?.recordId,
      answers,
    });
  }
}

