// ========== 维度 9: 并发请求 ==========
async function testConcurrency() {
  console.log('\n🔀 9. 并发请求');

  // 5个并发 GET
  const promises = Array.from({ length: 5 }, (_, i) =>
    GET(`/api/admin/exams?page=${i + 1}&size=5`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.code === 200);
  assert('5个并发 GET 都成功', allOk);

  // 5个并发考生端列表
  const studentPromises = Array.from({ length: 5 }, () =>
    GET('/api/exams?page=1&size=5')
  );
  const studentResults = await Promise.all(studentPromises);
  const allStudentOk = studentResults.every(r => r.code === 200);
  assert('5个并发考生端列表都成功', allStudentOk);
}

