  1→package com.exam.service;
  2→
  3→import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
  4→import com.baomidou.mybatisplus.core.metadata.IPage;
  5→import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
  6→import com.exam.dto.ExamCreateRequest;
  7→import com.exam.dto.ExamListResponse;
  8→import com.exam.dto.ExamUpdateRequest;
  9→import com.exam.entity.Exam;
 10→import com.exam.entity.QuestionBank;
 11→import com.exam.enums.ExamStatus;
 12→import com.exam.exception.BizException;
 13→import com.exam.exception.ErrorCode;
 14→import com.exam.mapper.ExamMapper;
 15→import com.exam.mapper.QuestionBankMapper;
 16→import lombok.extern.slf4j.Slf4j;
 17→import org.springframework.stereotype.Service;
 18→
 19→/**
 20→ * 试卷服务
 21→ */
 22→@Slf4j
 23→@Service
 24→public class ExamService {
 25→
 26→    private final ExamMapper examMapper;
 27→    private final QuestionBankMapper questionBankMapper;
 28→
 29→    public ExamService(ExamMapper examMapper, QuestionBankMapper questionBankMapper) {
 30→        this.examMapper = examMapper;
 31→        this.questionBankMapper = questionBankMapper;
 32→    }
 33→
 34→    /**
 35→     * 分页查询试卷列表（含答卷人数）
 36→     */
 37→    public IPage<ExamListResponse> listExams(int page, int size) {
 38→        return examMapper.selectExamListWithCount(new Page<>(page, size));
 39→    }
 40→
 41→    /**
 42→     * 创建试卷（初始状态为草稿）
 43→     */
 44→    public Exam create(ExamCreateRequest req, Long userId) {
 45→        Exam exam = Exam.builder()
 46→                .title(req.getTitle())
 47→                .timeLimitMin(req.getTimeLimitMin())
 48→                .showAnswer(req.getShowAnswer())
 49→                .showAnalysis(req.getShowAnalysis())
 50→                .questionCount(req.getQuestionCount())
 51→                .maxAttempts(req.getMaxAttempts())
 52→                .accessMode(req.getAccessMode())
 53→                .status(ExamStatus.DRAFT)
 54→                .createdBy(userId)
 55→                .build();
 56→        examMapper.insert(exam);
 57→        log.info("[lbl][Exam][CREATE] 创建试卷, examId={}, userId={}", exam.getId(), userId);
 58→        return exam;
 59→    }
 60→
 61→    /**
 62→     * 更新试卷（仅草稿状态可编辑）
 63→     */
 64→    public void update(Long id, ExamUpdateRequest req) {
 65→        Exam exam = getExamOrThrow(id);
 66→        if (exam.getStatus() != ExamStatus.DRAFT) {
 67→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
 68→        }
 69→        exam.setTitle(req.getTitle());
 70→        exam.setTimeLimitMin(req.getTimeLimitMin());
 71→        exam.setShowAnswer(req.getShowAnswer());
 72→        exam.setShowAnalysis(req.getShowAnalysis());
 73→        exam.setQuestionCount(req.getQuestionCount());
 74→        exam.setMaxAttempts(req.getMaxAttempts());
 75→        exam.setAccessMode(req.getAccessMode());
 76→        examMapper.updateById(exam);
 77→        log.info("[lbl][Exam][UPDATE] 更新试卷, examId={}", id);
 78→    }
 79→
 80→    /**
 81→     * 删除试卷（草稿或已关闭状态可删除，已发布状态需先关闭或取消发布）
 82→     */
 83→    public void delete(Long id) {
 84→        Exam exam = getExamOrThrow(id);
 85→        if (exam.getStatus() == ExamStatus.PUBLISHED) {
 86→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
 87→        }
 88→        examMapper.deleteById(id);
 89→        log.info("[lbl][Exam][DELETE] 删除试卷, examId={}, status={}", id, exam.getStatus());
 90→    }
 91→
 92→    /**
 93→     * 发布试卷（草稿 -> 已发布，需至少有一道题目）
 94→     */
 95→    public void publish(Long id) {
 96→        Exam exam = getExamOrThrow(id);
 97→        if (exam.getStatus() != ExamStatus.DRAFT) {
 98→            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
 99→        }
100→        // 校验题目数量
101→        long questionCount = questionBankMapper.selectCount(
102→                new LambdaQueryWrapper<QuestionBank>().eq(QuestionBank::getExamId, id));
103→        if (questionCount == 0) {
104→            throw new BizException(ErrorCode.EXAM_NO_QUESTIONS);
105→        }
106→        exam.setStatus(ExamStatus.PUBLISHED);
107→        examMapper.updateById(exam);
108→        log.info("[lbl][Exam][PUBLISH] 发布试卷, examId={}, questionCount={}", id, questionCount);
109→    }
110→
111→    /**
112→     * 取消发布试卷（已发布 -> 草稿）
113→     */
114→    public void unpublish(Long id) {
115→        Exam exam = getExamOrThrow(id);
116→        if (exam.getStatus() != ExamStatus.PUBLISHED) {
117→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
118→        }
119→        exam.setStatus(ExamStatus.DRAFT);
120→        examMapper.updateById(exam);
121→        log.info("[lbl][Exam][UNPUBLISH] 取消发布试卷, examId={}", id);
122→    }
123→
124→    /**
125→     * 关闭试卷（已发布 -> 已关闭）
126→     */
127→    public void close(Long id) {
128→        Exam exam = getExamOrThrow(id);
129→        if (exam.getStatus() != ExamStatus.PUBLISHED) {
130→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
131→        }
132→        exam.setStatus(ExamStatus.CLOSED);
133→        examMapper.updateById(exam);
134→        log.info("[lbl][Exam][CLOSE] 关闭试卷, examId={}", id);
135→    }
136→
137→    /**
138→     * 重新开放试卷（已关闭 -> 已发布）
139→     */
140→    public void reopen(Long id) {
141→        Exam exam = getExamOrThrow(id);
142→        if (exam.getStatus() != ExamStatus.CLOSED) {
143→            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
144→        }
145→        exam.setStatus(ExamStatus.PUBLISHED);
146→        examMapper.updateById(exam);
147→        log.info("[lbl][Exam][REOPEN] 重新开放试卷, examId={}", id);
148→    }
149→
150→    /**
151→     * 根据 ID 查询试卷，不存在则抛 NOT_FOUND
152→     */
153→    private Exam getExamOrThrow(Long id) {
154→        Exam exam = examMapper.selectById(id);
155→        if (exam == null) {
156→            throw new BizException(ErrorCode.NOT_FOUND);
157→        }
158→        return exam;
159→    }
160→}
