import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useRecordList } from "@/hooks/use-records"
import type { RecordDetail } from "@/hooks/use-records"

export const Route = createFileRoute("/_layout/records/")({
  component: RecordListPage,
})

/** 记录状态 badge 变体映射 */
const STATUS_VARIANT: Record<string, "default" | "destructive"> = {
  submitted: "default",
  timeout: "destructive",
}

function formatStatus(status: string, t: (key: string) => string): string {
  const map: Record<string, string> = {
    submitted: t("exam.statusSubmitted"),
    timeout: t("exam.statusTimeout"),
    in_progress: t("exam.statusInProgress"),
  }
  return map[status] ?? status
}

function formatDateTime(dateStr: string | null): string {
  if (!dateStr) return "-"
  return new Date(dateStr).toLocaleString()
}

function RecordListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useRecordList(page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  const handleRowClick = (record: RecordDetail) => {
    navigate({ to: `/records/${record.id}` })
  }

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">{t("nav.records")}</h1>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.loading")}
        </div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.noData")}
        </div>
      ) : (
        <>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("exam.examTitle")}</TableHead>
                <TableHead>{t("exam.score")}</TableHead>
                <TableHead>{t("exam.status")}</TableHead>
                <TableHead>{t("exam.examTime")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.records.map((record) => (
                <TableRow
                  key={record.id}
                  className="cursor-pointer hover:bg-muted/50"
                  onClick={() => handleRowClick(record)}
                >
                  <TableCell className="font-medium">
                    {record.examTitle}
                  </TableCell>
                  <TableCell>
                    {record.score !== null
                      ? `${record.score}${t("exam.scoreUnit")}`
                      : "-"}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={STATUS_VARIANT[record.status] ?? "default"}
                    >
                      {formatStatus(record.status, t)}
                    </Badge>
                  </TableCell>
                  <TableCell>{formatDateTime(record.startTime)}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("exam.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("exam.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

import { useQuery } from "@tanstack/react-query"
import { get } from "@/lib/api"
import type { PageResult } from "@/types"

/** 考试记录详情响应 */
export interface RecordDetail {
  id: number
  examId: number
  examTitle: string
  score: number | null
  startTime: string
  endTime: string | null
  status: string
  attemptNo: number
  answers?: Array<{
    questionId: number
    content: string
    optionA: string
    optionB: string
    optionC: string
    optionD: string
    userAnswer: string
    isCorrect: boolean
    correctAnswer?: string
    analysis?: string
  }>
}

const RECORDS_KEY = "records"

/** 考生端获取考试记录列表 */
export function useRecordList(page: number, size: number) {
  return useQuery<PageResult<RecordDetail>>({
    queryKey: [RECORDS_KEY, page, size],
    queryFn: () =>
      get<PageResult<RecordDetail>>(`/api/records?page=${page}&size=${size}`),
  })
}

/** 考生端获取单条考试记录详情（含答题明细） */
export function useRecordDetail(id: number) {
  return useQuery<RecordDetail>({
    queryKey: [RECORDS_KEY, id],
    queryFn: () => get<RecordDetail>(`/api/records/${id}`),
    enabled: id > 0,
  })
}

