import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Pencil, Trash2, Eye, Users, BarChart3, Send, XCircle, Undo2, RotateCcw, Type, ImageIcon } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useAdminExamList, useDeleteExam, usePublishExam, useUnpublishExam, useCloseExam, useReopenExam } from "@/hooks/use-admin-exams"
import type { Exam, ExamStatus } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/")({
  component: AdminExamListPage,
})

/** 状态 badge 样式映射 */
const STATUS_STYLE: Record<ExamStatus, string> = {
  draft: "bg-gray-100 text-gray-700 border-gray-200",
  published: "bg-green-50 text-green-700 border-green-200",
  closed: "bg-red-50 text-red-700 border-red-200",
}

const STATUS_LABEL: Record<ExamStatus, string> = {
  draft: "草稿",
  published: "已发布",
  closed: "已关闭",
}

function AdminExamListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useAdminExamList(page, pageSize)

  const deleteMutation = useDeleteExam()
  const publishMutation = usePublishExam()
  const unpublishMutation = useUnpublishExam()
  const closeMutation = useCloseExam()
  const reopenMutation = useReopenExam()

  const [deleteTarget, setDeleteTarget] = useState<Exam | null>(null)
  const [showTextActions, setShowTextActions] = useState(() => {
    try {
      return localStorage.getItem("exam-admin-text-actions") === "true"
    } catch {
      return false
    }
  })

  const toggleTextActions = () => {
    setShowTextActions((v) => {
      const next = !v
      try { localStorage.setItem("exam-admin-text-actions", String(next)) } catch { /* ignore */ }
      return next
    })
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(deleteTarget.id, {
      onSuccess: () => {
        toast.success(t("admin.deleteSuccess"))
        setDeleteTarget(null)
      },
      onError: (err) => toast.error(err.message),
    })
  }

  const handlePublish = (id: number) => {
    publishMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.publishSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleUnpublish = (id: number) => {
    unpublishMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.unpublishSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleReopen = (id: number) => {
    reopenMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.reopenSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleClose = (id: number) => {
    closeMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.closeSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  return (
    <div className="space-y-4">
      {/* 头部 */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("nav.examManagement")}</h1>
        <Button onClick={() => navigate({ to: "/admin/exams/create" })}>
          <Plus className="h-4 w-4" />
          {t("admin.createExam")}
        </Button>
      </div>

      {/* 表格 */}
      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("admin.examTitle")}</TableHead>
                <TableHead>{t("admin.status")}</TableHead>
                <TableHead>{t("admin.questionCount")}</TableHead>
                <TableHead>{t("admin.createdAt")}</TableHead>
                <TableHead>{t("admin.updatedAt")}</TableHead>
                <TableHead className="text-right">
                  <div className="flex items-center justify-end gap-1">
                    {t("common.actions")}
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      title={showTextActions ? t("common.iconMode") : t("common.textMode")}
                      onClick={toggleTextActions}
                    >
                      {showTextActions ? <ImageIcon className="h-3.5 w-3.5" /> : <Type className="h-3.5 w-3.5" />}
                    </Button>
                  </div>
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.records.map((exam) => (
                <TableRow key={exam.id}>
                  <TableCell className="font-medium">{exam.title}</TableCell>
                  <TableCell>
                    <Badge className={STATUS_STYLE[exam.status]}>
                      {STATUS_LABEL[exam.status]}
                    </Badge>
                  </TableCell>
                  <TableCell>{exam.questionCount}</TableCell>
                  <TableCell>{new Date(exam.createdAt).toLocaleDateString()}</TableCell>
                  <TableCell>{exam.updatedAt ? new Date(exam.updatedAt).toLocaleDateString() : "-"}</TableCell>
                  <TableCell>
                    <div className="flex flex-wrap justify-end gap-1">
                      {/* 草稿状态：编辑、发布、删除 */}
                      {exam.status === "draft" && (
                        <>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => navigate({ to: `/admin/exams/${exam.id}/edit` })}
                          >
                            <Pencil className="h-4 w-4" />
                            {showTextActions && t("common.edit")}
                          </Button>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => handlePublish(exam.id)}
                          >
                            <Send className="h-4 w-4" />
                            {showTextActions && t("admin.publish")}
                          </Button>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => setDeleteTarget(exam)}
                          >
                            <Trash2 className="h-4 w-4" />
                            {showTextActions && t("common.delete")}
                          </Button>
                        </>
                      )}
                      {/* 已发布状态：取消发布、关闭 */}
                      {exam.status === "published" && (
                        <>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => handleUnpublish(exam.id)}
                          >
                            <Undo2 className="h-4 w-4" />
                            {showTextActions && t("admin.unpublish")}
                          </Button>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => handleClose(exam.id)}
                          >
                            <XCircle className="h-4 w-4" />
                            {showTextActions && t("admin.close")}
                          </Button>
                        </>
                      )}
                      {/* 已关闭状态：重新发布、删除 */}
                      {exam.status === "closed" && (
                        <>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => handleReopen(exam.id)}
                          >
                            <RotateCcw className="h-4 w-4" />
                            {showTextActions && t("admin.reopen")}
                          </Button>
                          <Button
                            variant="ghost"
                            size={showTextActions ? "sm" : "icon"}
                            onClick={() => setDeleteTarget(exam)}
                          >
                            <Trash2 className="h-4 w-4" />
                            {showTextActions && t("common.delete")}
                          </Button>
                        </>
                      )}
                      {/* 所有状态：题目管理、白名单、分析 */}
                      <Button
                        variant="ghost"
                        size={showTextActions ? "sm" : "icon"}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/questions` })}
                      >
                        <Eye className="h-4 w-4" />
                        {showTextActions && t("admin.manageQuestions")}
                      </Button>
                      <Button
                        variant="ghost"
                        size={showTextActions ? "sm" : "icon"}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/whitelist` })}
                      >
                        <Users className="h-4 w-4" />
                        {showTextActions && t("admin.whitelist")}
                      </Button>
                      <Button
                        variant="ghost"
                        size={showTextActions ? "sm" : "icon"}
                        onClick={() => navigate({ to: `/admin/exams/${exam.id}/analysis` })}
                      >
                        <BarChart3 className="h-4 w-4" />
                        {showTextActions && t("admin.analysisTab")}
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("admin.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("admin.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>
              {t("admin.confirmDeleteDesc", { title: deleteTarget?.title })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

