        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <>
          <div className="rounded-lg border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="min-w-[160px]">{t("admin.examTitle")}</TableHead>
                  <TableHead className="w-[90px]">{t("admin.status")}</TableHead>
                  <TableHead className="w-[80px] text-center">{t("admin.questionCount")}</TableHead>
                  <TableHead className="w-[110px]">{t("admin.createdAt")}</TableHead>
                  <TableHead className="w-[110px]">{t("admin.updatedAt")}</TableHead>
                  <TableHead className="min-w-[260px] text-right">{t("common.actions")}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {data.records.map((exam) => (
                  <TableRow key={exam.id}>
                    <TableCell className="font-medium">{exam.title}</TableCell>
                    <TableCell>
                      <Badge className={STATUS_STYLE[exam.status]}>
                        {t(STATUS_LABEL_KEY[exam.status])}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-center">{exam.questionCount}</TableCell>
                    <TableCell className="text-muted-foreground text-sm">{new Date(exam.createdAt).toLocaleDateString()}</TableCell>
                    <TableCell className="text-muted-foreground text-sm">{exam.updatedAt ? new Date(exam.updatedAt).toLocaleDateString() : "-"}</TableCell>
                    <TableCell>
                      <div className="flex items-center justify-end gap-0.5">
                        {/* 状态操作按钮 */}
                        {exam.status === "draft" && (
                          <>
                            <Button variant="ghost" size="icon" className="h-8 w-8" title={t("common.edit")} onClick={() => navigate({ to: `/admin/exams/${exam.id}/edit` })}>
                              <Pencil className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-green-600 hover:text-green-700" title={t("admin.publish")} onClick={() => handlePublish(exam.id)}>
                              <Send className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive hover:text-destructive" title={t("common.delete")} onClick={() => setDeleteTarget(exam)}>
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </>
                        )}
                        {exam.status === "published" && (
                          <>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-orange-500 hover:text-orange-600" title={t("admin.unpublish")} onClick={() => handleUnpublish(exam.id)}>
