                        {exam.status === "closed" && (
                          <>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-blue-500 hover:text-blue-600" title={t("admin.reopen")} onClick={() => handleReopen(exam.id)}>
                              <RotateCcw className="h-4 w-4" />
