  closed: "bg-red-50 text-red-700 border-red-200",
}

const STATUS_LABEL_KEY: Record<ExamStatus, string> = {
  draft: "admin.statusDraft",
  published: "admin.statusPublished",
  closed: "admin.statusClosed",
}

